mapper.update:
UPDATE password_reset_code
SET status = #{status},
    updated_at = #{updatedAt}
WHERE email = #{email}
  AND scene = #{scene}
  AND status = 0

UPDATE password_reset_code
SET status = 1,
    used_at = #{usedAt},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE password_reset_code
SET attempt_count = attempt_count + 1,
    updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT COUNT(1)
FROM password_reset_code
WHERE email = #{email}
  AND scene = #{scene}
  AND created_at >= #{createdAt}

SELECT COUNT(1)
FROM password_reset_code
WHERE request_ip = #{requestIp}
  AND scene = #{scene}
  AND created_at >= #{createdAt}
